#include <iostream>
#include <string>

class Date {
private:
    int day;
    int month;
    int year;

public:
    Date(int d, int m, int y) : day(d), month(m), year(y) {}

    bool operator==(const Date& other) const {
        return day == other.day && month == other.month && year == other.year;
    }

    void print() const {
        std::cout << day << "/" << month << "/" << year;
    }
};

int main() {
    Date d1(10, 5, 2023);
    Date d2(10, 5, 2023);
    Date d3(11, 5, 2023);
    Date d4(30, 2, 2023); // Invalid date
    Date d5(30, 2, 2023); // Invalid date

    std::cout << (d1 == d2 ? "true" : "false") << std::endl;
    std::cout << (d1 == d3 ? "true" : "false") << std::endl;
    std::cout << (d4 == d5 ? "true" : "false") << std::endl;
    std::cout << (d1 == d4 ? "true" : "false") << std::endl;

    return 0;
}
